import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { Dashboard } from '../../core/models';

/**
 * SiteView roll-up dashboard — consumes GET /dashboard/:projectId.
 * Renders a schedule-health gauge (SVG donut), per-phase budget variance
 * (red when actual > planned) and the open-hazard count.
 *
 * DATA CONTRACT: `dashboard` is a signal<Dashboard | null> of mock data; the
 * service_agent stage clears it and wires ApiService.getDashboard() in ngOnInit.
 */
@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.css',
})
export class DashboardComponent implements OnInit {
  readonly projectId = signal<string>('');

  readonly dashboard = signal<Dashboard | null>({
    scheduleHealth: { onTrack: 5, total: 8 },
    phases: [
      { phaseId: 'ph1', phaseName: 'Site Prep & Foundation', plannedCents: 4200000, actualCents: 3980000, overBudget: false },
      { phaseId: 'ph2', phaseName: 'Structure & Envelope', plannedCents: 8600000, actualCents: 9350000, overBudget: true },
      { phaseId: 'ph3', phaseName: 'Interior & Fit-out', plannedCents: 5100000, actualCents: 2400000, overBudget: false },
    ],
    openHazards: 2,
  });

  // Gauge geometry (donut).
  readonly R = 52;
  readonly C = 2 * Math.PI * 52;

  readonly healthPct = computed(() => {
    const d = this.dashboard();
    if (!d || d.scheduleHealth.total === 0) return 0;
    return Math.round((d.scheduleHealth.onTrack / d.scheduleHealth.total) * 100);
  });
  readonly dashOffset = computed(() => this.C * (1 - this.healthPct() / 100));
  readonly healthTone = computed(() => {
    const p = this.healthPct();
    return p >= 75 ? 'ok' : p >= 50 ? 'warn' : 'danger';
  });

  readonly totalPlanned = computed(() =>
    (this.dashboard()?.phases ?? []).reduce((s, p) => s + p.plannedCents, 0),
  );
  readonly totalActual = computed(() =>
    (this.dashboard()?.phases ?? []).reduce((s, p) => s + p.actualCents, 0),
  );
  readonly overallOver = computed(() => this.totalActual() > this.totalPlanned());

  constructor(private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.route.parent?.paramMap.subscribe((p) => this.projectId.set(p.get('id') ?? ''));
  }

  dollars(cents: number): string {
    return (cents / 100).toLocaleString('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 });
  }
  /** Bar width % for a phase's actual vs the largest planned value on screen. */
  barPct(cents: number): number {
    const max = Math.max(this.totalPlanned(), this.totalActual(), 1);
    const phaseMax = Math.max(...(this.dashboard()?.phases ?? []).map((p) => Math.max(p.plannedCents, p.actualCents)), 1);
    return Math.round((cents / phaseMax) * 100);
  }
}
